<template>
	<view class="container">
		<view class="form-container">
			<!-- еҹәжң¬дҝЎжҒҜ -->
			<view class="form-section">
				<view class="section-title">
					<text class="title-icon">рҹ‘Ө</text>
					<text class="title-text">еҹәжң¬дҝЎжҒҜ</text>
				</view>

				<!-- дәәж•° -->
				<view class="form-item required">
					<text class="label">йў„зәҰдәәж•°</text>
					<view class="input-wrapper">
						<view class="stepper">
							<button class="stepper-btn" @click="decreasePerson">-</button>
							<input class="stepper-input" type="number" v-model.number="formData.personCount"
								@input="onPersonCountInput" />
							<button class="stepper-btn" @click="increasePerson">+</button>
						</view>
					</view>
				</view>

				<!-- иҒ”зі»дәәе§“еҗҚ -->
				<view class="form-item required">
					<text class="label">иҒ”зі»дәәе§“еҗҚ</text>
					<view class="input-wrapper">
						<input class="input" v-model="formData.name" placeholder="иҜ·иҫ“е…ҘиҒ”зі»дәәе§“еҗҚ" />
					</view>
				</view>

				<!-- жүӢжңәеҸ· -->
				<view class="form-item required">
					<text class="label">жүӢжңәеҸ·з Ғ</text>
					<view class="input-wrapper">
						<input class="input" type="number" maxlength="11" v-model="formData.phone"
							placeholder="иҜ·иҫ“е…ҘжүӢжңәеҸ·з Ғ" />
					</view>
				</view>

				<!-- иә«д»ҪиҜҒеҸ· -->
				<view class="form-item required">
					<text class="label">иә«д»ҪиҜҒеҸ·</text>
					<view class="input-wrapper">
						<input class="input" maxlength="18" v-model="formData.idCard" placeholder="иҜ·иҫ“е…Ҙиә«д»ҪиҜҒеҸ·з Ғ" />
					</view>
				</view>


				<!-- йў„зәҰж—Ҙжңҹ -->
				<view class="form-item required">
					<text class="label">йў„зәҰж—Ҙжңҹ</text>
					<view class="input-wrapper">
						<picker mode="date" :start="minDate" :end="maxDate" @change="onDateChange">
							<view class="picker">
								{{ formData.bookingDate || 'иҜ·йҖүжӢ©йў„зәҰж—Ҙжңҹ' }}
							</view>
						</picker>
					</view>
				</view>

				<!-- йў„зәҰж—¶й—ҙж®ө -->
				<view class="form-item required">
					<text class="label">йў„зәҰж—¶й—ҙж®ө</text>
					<view class="time-period-group">
						<view class="time-period-item" :class="{ active: formData.timeSlot === 'morning' }"
							@click="onTimePeriodChange('morning')">
							<view class="period-info">
								<text class="period-title">дёҠеҚҲ</text>
								<text class="period-time">08:00-12:00</text>
							</view>
							<view class="period-check" v-if="formData.timeSlot === 'morning'">вң“</view>
						</view>
						<view class="time-period-item" :class="{ active: formData.timeSlot === 'afternoon' }"
							@click="onTimePeriodChange('afternoon')">
							<view class="period-info">
								<text class="period-title">дёӢеҚҲ</text>
								<text class="period-time">12:00-18:00</text>
							</view>
							<view class="period-check" v-if="formData.timeSlot === 'afternoon'">вң“</view>
						</view>
					</view>
				</view>
			</view>

			<!-- еҮәиЎҢж–№ејҸ -->
			<view class="form-section">
				<view class="section-title">
					<text class="title-icon">рҹҡ—</text>
					<text class="title-text">еҮәиЎҢж–№ејҸ</text>
				</view>

				<view class="form-item">
					<text class="label required-label">йҖүжӢ©еҮәиЎҢж–№ејҸ</text>
					<view class="travel-type-group">
						<view class="travel-type-item" :class="{ active: formData.travelMode === item.value }"
							v-for="item in travelModeList" :key="item.value" @click="onTravelTypeChange(item.value)">
							<text class="travel-icon">{{ item.icon }}</text>
							<text class="travel-label">{{ item.label }}</text>
							<view class="travel-check" v-if="formData.travelMode === item.value">вң“</view>
						</view>
					</view>
				</view>
			</view>

			<!-- иҮӘй©ҫдҝЎжҒҜ -->
			<view class="form-section" v-if="formData.travelMode === 'selfDriving'">
				<view class="section-title">
					<text class="title-icon">рҹҡҷ</text>
					<text class="title-text">иҪҰиҫҶдҝЎжҒҜ</text>
				</view>

				<!-- иҪҰиҫҶзұ»еһӢ -->
				<view class="form-item required">
					<text class="label">иҪҰиҫҶзұ»еһӢ</text>
					<view class="input-wrapper">
						<picker mode="selector" :range="vehicleTypes" range-key="label" @change="onVehicleTypeChange">
							<view class="picker">
								{{ getVehicleTypeLabel() || 'иҜ·йҖүжӢ©иҪҰиҫҶзұ»еһӢ' }}
							</view>
						</picker>
					</view>
				</view>

				<!-- иҪҰзүҢеҸ· -->
				<view class="form-item required">
					<text class="label">иҪҰзүҢеҸ·</text>
					<view class="input-wrapper">
						<input class="input" v-model="formData.licensePlate" placeholder="иҜ·иҫ“е…ҘиҪҰзүҢеҸ·" />
					</view>
				</view>
			</view>

			<!-- и§Ӯе…үеӣўдҝЎжҒҜ -->
			<view class="form-section" v-if="formData.travelMode === 'tourGroup'">
				<view class="section-title">
					<text class="title-icon">рҹ‘Ҙ</text>
					<text class="title-text">и§Ӯе…үеӣўдҝЎжҒҜ</text>
				</view>

				<!-- ж—…иЎҢзӨҫеҗҚз§° -->
				<view class="form-item required">
					<text class="label">ж—…иЎҢзӨҫеҗҚз§°</text>
					<view class="input-wrapper">
						<input class="input" v-model="formData.tourGroupName" placeholder="иҜ·иҫ“е…Ҙж—…иЎҢзӨҫеҗҚз§°" />
					</view>
				</view>

				<!-- еӣўйҳҹзј–еҸ· -->
				<view class="form-item required">
					<text class="label">еӣўйҳҹзј–еҸ·</text>
					<view class="input-wrapper">
						<input class="input" v-model="formData.tourNumber" placeholder="иҜ·иҫ“е…Ҙеӣўйҳҹзј–еҸ·" />
					</view>
				</view>
			</view>

			<!-- еӨҮжіЁдҝЎжҒҜ -->
			<view class="form-section">
				<view class="section-title">
					<text class="title-icon">рҹ“қ</text>
					<text class="title-text">еӨҮжіЁдҝЎжҒҜ</text>
				</view>

				<view class="form-item">
					<textarea class="textarea" v-model="formData.remarks" placeholder="иҜ·иҫ“е…ҘеӨҮжіЁдҝЎжҒҜпјҲйҖүеЎ«пјү" maxlength="200" />
					<text class="char-count">{{ formData.remarks.length }}/200</text>
				</view>
			</view>
		</view>

		<!-- жҸҗдәӨжҢүй’® -->
		<view class="submit-section" v-if="!formData.bookingId">
			<button class="submit-btn" @click="handleSubmit">
				<text class="submit-icon"></text>
				<text>з«ӢеҚійў„зәҰ</text>
			</button>
		</view>
	</view>
</template>

<script>
	import {
		request
	} from '../../utils/request';

	export default {
		data() {
			return {
				id: '', // жҷҜеҢәIDпјҢд»Һи·Ҝз”ұеҸӮж•°иҺ·еҸ–
				formData: {
					name: 'zhang', // иҒ”зі»дәәе§“еҗҚ
					phone: '13261732722', // иҒ”зі»дәәжүӢжңәеҸ·
					idCard: '410621200008210019', // иҒ”зі»дәәиә«д»ҪиҜҒеҸ·
					bookingDate: '', // йў„зәҰж—Ҙжңҹ
					timeSlot: 'morning', // йў„зәҰж—¶й—ҙж®өпјҲmorning/afternoonпјү
					travelMode: 'selfDriving', // еҮәиЎҢж–№ејҸпјҲscenicBus/selfDriving/tour_groupпјү
					licensePlate: 'дә¬A12345', // иҪҰзүҢеҸ·пјҲиҮӘй©ҫж—¶еҝ…еЎ«пјү
					vehicleType: 'wheelMotorcycle', // иҪҰиҫҶзұ»еһӢпјҲиҮӘй©ҫж—¶еҝ…еЎ«пјү
					tourGroupName: '', // ж—…жёёеӣўеҗҚз§°пјҲж—…жёёеӣўж—¶еҝ…еЎ«пјү
					tourOrderNumber: '', // ж—…жёёеӣўи®ўеҚ•зј–еҸ·пјҲж—…жёёеӣўж—¶еҝ…еЎ«пјү
					personCount: 1, // йў„зәҰдәәж•°
					remarks: '' // еӨҮжіЁдҝЎжҒҜ
				},
				travelModeList: [{
						label: 'жҷҜеҢәж‘ҶжёЎиҪҰ',
						value: 'scenicBus',
						icon: 'рҹҡҢ'
					},
					{
						label: 'иҮӘй©ҫеҮәиЎҢ',
						value: 'selfDriving',
						icon: 'рҹҡ—'
					},
					// {
					// 	label: 'и§Ӯе…үеӣў',
					// 	value: 'tourGroup',
					// 	icon: 'рҹ‘Ҙ'
					// }
				],
				vehicleTypes: [{
						label: 'ж‘©жүҳ',
						value: 'wheelMotorcycle'
					},
					{
						label: 'е°ҸеһӢе®ўиҪҰ',
						value: 'smallCar'
					},
				],
				minDate: '',
				maxDate: ''
			}
		},
		onLoad(options) {
			// жЈҖжҹҘжҳҜеҗҰжҗәеёҰ bookingId еҸӮж•°
			if (options.bookingId) {
				this.getBookingDetail(options.bookingId);
			} else {
				// и®ҫзҪ®ж—ҘжңҹиҢғеӣҙпјҲд»ҠеӨ©еҲ°3дёӘжңҲеҗҺпјү
				const today = new Date();
				const maxDay = new Date();
				maxDay.setMonth(maxDay.getMonth() + 3);

				this.minDate = this.formatDate(today);
				this.maxDate = this.formatDate(maxDay);
			}
		},
		// еҲҶдә«й…ҚзҪ®
		onShareAppMessage() {
			return {
				title: 'йЈҺиҪҰеӨ©и·Ҝ - жөӘжј«йЈҺиҪҰд№Ӣж—…зӯүдҪ жқҘ',
				path: '/pages/index/index'
			}
		},
		methods: {
			// дәәж•°еўһеҠ 
			increasePerson() {
				if (this.formData.personCount < 99) {
					this.formData.personCount++;
				}
			},
			// дәәж•°еҮҸе°‘
			decreasePerson() {
				if (this.formData.personCount > 1) {
					this.formData.personCount--;
				}
			},
			// дәәж•°иҫ“е…Ҙ
			onPersonCountInput(e) {
				let value = parseInt(e.detail.value) || 1;
				if (value < 1) value = 1;
				if (value > 99) value = 99;
				this.formData.personCount = value;
			},
			// е№ҙйҫ„ж®өйҖүжӢ©
			onAgeRangeChange(e) {
				this.formData.ageRange = this.ageRanges[e.detail.value];
			},
			// ж—ҘжңҹйҖүжӢ©
			onDateChange(e) {
				this.formData.bookingDate = e.detail.value;
			},
			// ж—¶й—ҙж®өйҖүжӢ©
			onTimePeriodChange(period) {
				this.formData.timeSlot = period;
			},
			// еҮәиЎҢж–№ејҸйҖүжӢ©
			onTravelTypeChange(value) {
				this.formData.travelMode = value;
			},
			// иҪҰиҫҶзұ»еһӢйҖүжӢ©
			onVehicleTypeChange(e) {
				this.formData.vehicleType = this.vehicleTypes[e.detail.value].value;
			},
			// иҺ·еҸ–иҪҰиҫҶзұ»еһӢж Үзӯҫ
			getVehicleTypeLabel() {
				const type = this.vehicleTypes.find(item => item.value === this.formData.vehicleType);
				return type ? type.label : '';
			},
			// ж јејҸеҢ–ж—Ҙжңҹ
			formatDate(date) {
				const year = date.getFullYear();
				const month = String(date.getMonth() + 1).padStart(2, '0');
				const day = String(date.getDate()).padStart(2, '0');
				return `${year}-${month}-${day}`;
			},
			// йӘҢиҜҒжүӢжңәеҸ·
			validatePhone(phone) {
				const reg = /^1[3-9]\d{9}$/;
				return reg.test(phone);
			},
			// йӘҢиҜҒиә«д»ҪиҜҒеҸ·
			validateIdCard(idCard) {
				const reg = /(^\d{15}$)|(^\d{18}$)|(^\d{17}(\d|X|x)$)/;
				return reg.test(idCard);
			},
			// йӘҢиҜҒиҪҰзүҢеҸ·
			validatePlateNumber(plateNumber) {
				const reg = /^[дә¬жҙҘжІӘжёқеҶҖиұ«дә‘иҫҪй»‘ж№ҳзҡ–йІҒж–°иӢҸжөҷиөЈй„ӮжЎӮз”ҳжҷӢи’ҷйҷ•еҗүй—ҪиҙөзІӨйқ’и—Ҹе·қе®ҒзҗјдҪҝйўҶ][A-Z][A-Z0-9]{4,5}[A-Z0-9жҢӮеӯҰиӯҰжёҜжҫі]$/;
				return reg.test(plateNumber);
			},
			// иЎЁеҚ•йӘҢиҜҒ
			validateForm() {
				// йӘҢиҜҒдәәж•°
				if (!this.formData.personCount || this.formData.personCount < 1) {
					uni.showToast({
						title: 'иҜ·иҫ“е…Ҙйў„зәҰдәәж•°',
						icon: 'none'
					});
					return false;
				}

				// йӘҢиҜҒиҒ”зі»дәәе§“еҗҚ
				if (!this.formData.name.trim()) {
					uni.showToast({
						title: 'иҜ·иҫ“е…ҘиҒ”зі»дәәе§“еҗҚ',
						icon: 'none'
					});
					return false;
				}

				// йӘҢиҜҒжүӢжңәеҸ·
				if (!this.formData.phone) {
					uni.showToast({
						title: 'иҜ·иҫ“е…ҘжүӢжңәеҸ·з Ғ',
						icon: 'none'
					});
					return false;
				}
				if (!this.validatePhone(this.formData.phone)) {
					uni.showToast({
						title: 'иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәеҸ·з Ғ',
						icon: 'none'
					});
					return false;
				}

				// йӘҢиҜҒиә«д»ҪиҜҒеҸ·
				if (!this.formData.idCard) {
					uni.showToast({
						title: 'иҜ·иҫ“е…Ҙиә«д»ҪиҜҒеҸ·з Ғ',
						icon: 'none'
					});
					return false;
				}
				if (!this.validateIdCard(this.formData.idCard)) {
					uni.showToast({
						title: 'иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„иә«д»ҪиҜҒеҸ·з Ғ',
						icon: 'none'
					});
					return false;
				}

				// йӘҢиҜҒйў„зәҰж—Ҙжңҹ
				if (!this.formData.bookingDate) {
					uni.showToast({
						title: 'иҜ·йҖүжӢ©йў„зәҰж—Ҙжңҹ',
						icon: 'none'
					});
					return false;
				}

				// йӘҢиҜҒйў„зәҰж—¶й—ҙж®ө
				if (!this.formData.timeSlot) {
					uni.showToast({
						title: 'иҜ·йҖүжӢ©йў„зәҰж—¶й—ҙж®ө',
						icon: 'none'
					});
					return false;
				}
				// еҰӮжһңжҳҜиҮӘй©ҫпјҢйӘҢиҜҒиҪҰиҫҶдҝЎжҒҜ
				if (this.formData.travelType === 'selfDriving') {
					if (!this.formData.vehicleType) {
						uni.showToast({
							title: 'иҜ·йҖүжӢ©иҪҰиҫҶзұ»еһӢ',
							icon: 'none'
						});
						return false;
					}
					if (!this.formData.licensePlate) {
						uni.showToast({
							title: 'иҜ·иҫ“е…ҘиҪҰзүҢеҸ·',
							icon: 'none'
						});
						return false;
					}
					if (!this.validatePlateNumber(this.formData.licensePlate)) {
						uni.showToast({
							title: 'иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„иҪҰзүҢеҸ·',
							icon: 'none'
						});
						return false;
					}
				}

				// // еҰӮжһңжҳҜи§Ӯе…үеӣўпјҢйӘҢиҜҒи§Ӯе…үеӣўдҝЎжҒҜ
				// if (this.formData.travelType === 'tour-group') {
				// 	if (!this.formData.tourInfo.agencyName.trim()) {
				// 		uni.showToast({
				// 			title: 'иҜ·иҫ“е…Ҙж—…иЎҢзӨҫеҗҚз§°',
				// 			icon: 'none'
				// 		});
				// 		return false;
				// 	}
				// 	if (!this.formData.tourInfo.groupNumber.trim()) {
				// 		uni.showToast({
				// 			title: 'иҜ·иҫ“е…Ҙеӣўйҳҹзј–еҸ·',
				// 			icon: 'none'
				// 		});
				// 		return false;
				// 	}
				// 	if (!this.formData.tourInfo.busPlateNumber) {
				// 		uni.showToast({
				// 			title: 'иҜ·иҫ“е…ҘеӨ§е·ҙиҪҰзүҢеҸ·',
				// 			icon: 'none'
				// 		});
				// 		return false;
				// 	}
				// 	if (!this.validatePlateNumber(this.formData.tourInfo.busPlateNumber)) {
				// 		uni.showToast({
				// 			title: 'иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„еӨ§е·ҙиҪҰзүҢеҸ·',
				// 			icon: 'none'
				// 		});
				// 		return false;
				// 	}
				// }

				return true;
			},
			// жҸҗдәӨиЎЁеҚ•
			handleSubmit() {
				// йӘҢиҜҒиЎЁеҚ•
				if (!this.validateForm()) {
					return;
				}

				// жҳҫзӨәеҠ иҪҪжҸҗзӨә
				uni.showLoading({
					title: 'жҸҗдәӨдёӯ...'
				});
				// зӣҙжҺҘжҸҗдәӨ formDataпјҢеӯ—ж®өдёҺеҗҺз«ҜдҝқжҢҒдёҖиҮҙ
				const submitData = {
				    ...this.formData,
				    wechatOpenId: uni.getStorageSync('openid')
				};
				request({
					method: 'POST',
					url: '/bookings',
					data: submitData
				}).then(res => {
                                    if(res.success) {
                                        uni.showToast({
                                            title: 'йў„зәҰжҲҗеҠҹ',
                                            icon: 'success'
                                        });
                                        uni.reLaunch({
                                            url: '/pages/booking/booking'
                                        });
                                    } else {
                                        uni.showToast({
                                            title: 'йў„зәҰеӨұиҙҘпјҢиҜ·зЁҚеҗҺеҶҚиҜ•',
                                            icon: 'error'
                                        });
                                    }
				}).catch(err => {
                                    console.log('йў„зәҰжҸҗдәӨеӨұиҙҘ:', err);
                                    uni.showToast({
